\procedure minver-manager()

<div class="mv-manager">

<!-- Top actions -->
<div class="mv-manager-actions-bar">
	<$button class="tc-btn-big-green" style="margin-right:8px">
		<$action-minver op="export"/>
		Export all Snapshots
	</$button>
	<$button class="tc-btn-big-green" style="margin-right:8px">
		<$action-confirm $message="Import snapshots from $:/minver/export? This will merge with existing snapshots.">
		<$action-minver op="import"/>
		</$action-confirm>
		Import Snapshots
	</$button>
	<$button class="tc-btn-big-green mv-btn-danger" style="margin-right:8px">
		<$action-confirm $message="Clear ALL snapshots from browser storage? This cannot be undone.">
		<$action-minver op="clean-all"/>
		</$action-confirm>
		Clear all Snapshots
	</$button>
</div>

<!-- Draggable export tiddler -->
<%if [[$:/minver/export]is[tiddler]] %>
<div class="mv-export-drag">
	<$draggable tiddler="$:/minver/export" class="mv-export-drag-handle">
		<span class="mv-export-drag-icon">
			<$transclude $tiddler="$:/plugins/rimir/minver/icon/download"/>
		</span>
		Drag <code>$:/minver/export</code> to another wiki to transfer snapshots
	</$draggable>
	<$button class="tc-btn-invisible mv-download-btn" tooltip="Download as JSON file">
		<$action-sendmessage $message="tm-download-file" $param="$:/minver/export" filename="minver-snapshots.json"/>
		<$transclude $tiddler="$:/plugins/rimir/minver/icon/download"/>
		Download
	</$button>
</div>
<%endif%>

<div class="rr-input-row" style="margin:8px 0">
	<$edit-text tiddler="$:/temp/minver/manager-filter" tag="input" placeholder="Filter tiddler titles..." class="rr-input" default=""/>
</div>

<$let filterText={{{ [[$:/temp/minver/manager-filter]get[text]else[]] }}}>

<!-- List all tiddlers that have snapshots -->
<$list filter="[prefix[$:/temp/minver/snapshots/]removeprefix[$:/temp/minver/snapshots/]!is[blank]search<filterText>sort[]]" variable="tiddlerTitle" emptyMessage="<div class='rr-status-info'>No snapshots found.</div>">
	<$let
		snapshotsTiddler={{{ [[$:/temp/minver/snapshots/]addsuffix<tiddlerTitle>] }}}
		managerState={{{ [[$:/state/minver/manager/]addsuffix<tiddlerTitle>] }}}
		snapshotCount={{{ [<snapshotsTiddler>get[text]jsonindexes[]count[]] }}}
	>
	<div class="mv-manager-tiddler">
		<div class="mv-manager-header">
			<$button class="tc-btn-invisible mv-manager-toggle">
				<$action-setfield $tiddler=<<managerState>> text={{{ [<managerState>get[text]match[open]then[closed]else[open]] }}}/>
