<$reveal type="nomatch" state="$:/temp/minver/cg-recording" text="" default="">
<$button tooltip="Stop recording changes" aria-label="Stop recording" class=<<tv-config-toolbar-class>>>
<$action-minver op="cg-stop"/>
<%if [<tv-config-toolbar-icons>match[yes]] %>
<span class="mv-cg-recording-icon">
<$transclude $tiddler="$:/plugins/rimir/minver/icon/stop"/>
</span>
<%endif%>
<%if [<tv-config-toolbar-text>match[yes]] %>
